import{_ as t,o as a,i,ad as n}from"./chunks/framework.Cq4hg8jX.js";const p=JSON.parse('{"title":"SSR & Production","description":"Why server-side rendering needs no special handling, and what to expect from PikaCSS in dev and production builds.","frontmatter":{"title":"SSR & Production","description":"Why server-side rendering needs no special handling, and what to expect from PikaCSS in dev and production builds.","relatedPackages":["@pikacss/unplugin-pikacss","@pikacss/integration","@pikacss/nuxt-pikacss"],"relatedSources":["packages/unplugin/src/index.ts","packages/integration/src/ctx.ts","packages/nuxt/src/index.ts"],"category":"integrations","order":24},"headers":[],"relativePath":"integrations/ssr-and-production.md","filePath":"integrations/ssr-and-production.md"}'),s={name:"integrations/ssr-and-production.md"};function r(o,e,d,l,c,h){return a(),i("div",null,[...e[0]||(e[0]=[n('<div style="display:none;" hidden="true" aria-hidden="true" data-nosnippet>Are you an LLM? You can read better optimized documentation at /integrations/ssr-and-production.md for this page in Markdown format</div><h1 id="ssr-production" tabindex="-1">SSR &amp; Production <a class="header-anchor" href="#ssr-production" aria-label="Permalink to “SSR &amp; Production”">​</a></h1><p>PikaCSS output is a static CSS file produced at build time. That single fact answers most SSR and production questions.</p><h2 id="ssr-ssg-and-streaming-just-work" tabindex="-1">SSR, SSG, and Streaming Just Work <a class="header-anchor" href="#ssr-ssg-and-streaming-just-work" aria-label="Permalink to “SSR, SSG, and Streaming Just Work”">​</a></h2><p>There is no runtime style injection and no style registry to flush:</p><ul><li>Every <code>pika()</code> call is replaced with a class-name string literal during the build — components render plain strings on the server exactly as they do in the browser.</li><li>All generated styles live in one CSS file (<code>pika.gen.css</code> by default). The <code>import &#39;pika.css&#39;</code> specifier resolves to that file, and your bundler handles it like any other stylesheet import.</li></ul><p>So server-side rendering, static site generation, and streaming responses need no PikaCSS-specific handling: if your setup can serve a regular imported stylesheet, it can serve PikaCSS. There is no <code>extractCriticalToChunks</code>, no <code>ServerStyleSheet</code>, no hydration mismatch surface from styling.</p><p>For Nuxt specifically, the <code>@pikacss/nuxt-pikacss</code> module registers a Nuxt plugin template whose only job is <code>import &quot;pika.css&quot;</code> — nothing else is added to the server or client runtime. See <a href="/integrations/nuxt.html">Nuxt</a>.</p><h2 id="production-builds" tabindex="-1">Production Builds <a class="header-anchor" href="#production-builds" aria-label="Permalink to “Production Builds”">​</a></h2><p>In build mode the plugin scans all files matched by <code>scan.include</code> up front, collects every <code>pika()</code> usage, and writes the complete CSS file before bundling continues. The output contains:</p><ul><li>the <code>@layer</code> order declaration,</li><li>preflights (with unused variables and keyframes pruned),</li><li>the deduplicated atomic classes — sized by unique declarations, not call sites (see <a href="/getting-started/how-pikacss-generates-css.html">How PikaCSS Generates CSS</a>).</li></ul><p>The result passes through your bundler&#39;s normal CSS pipeline (minification, hashing, code splitting) untouched by PikaCSS.</p><h2 id="what-triggers-a-reload-in-dev" tabindex="-1">What Triggers a Reload in Dev <a class="header-anchor" href="#what-triggers-a-reload-in-dev" aria-label="Permalink to “What Triggers a Reload in Dev”">​</a></h2><p>The dev server re-creates the engine (and regenerates both output files) when:</p><ul><li><strong>The config file changes.</strong> The resolved <code>pika.config.*</code> file is watched; a content change reloads the config and rebuilds the engine.</li><li><strong>A config dependency changes.</strong> Plugins that load external files register them via <code>engine.addConfigDependency(path)</code> — for example, <a href="/official-plugins/design-tokens.html">@pikacss/plugin-design-tokens</a> registers its token source files. Those paths are watched the same way as the config file.</li></ul><p>Both paths rely on the bundler&#39;s file watcher (esbuild is the exception — it has no watch-based reload path). Ordinary source edits do not re-create the engine; they only add or update the affected file&#39;s usages, and the generated files are rewritten only when the resolved styles actually changed.</p><h2 id="type-level-performance" tabindex="-1">Type-Level Performance <a class="header-anchor" href="#type-level-performance" aria-label="Permalink to “Type-Level Performance”">​</a></h2><p>The size of the generated <code>pika.gen.ts</code> (autocomplete unions, preview overloads) grows with your project. TypeScript type-system cost is tracked with an in-repo benchmark suite (<code>scripts/type-bench/</code>) that measures check time, instantiations, and IDE latency across usage scales and TS versions — so regressions in type performance are measured, not guessed. No absolute numbers are published because they depend heavily on project shape and hardware.</p><h2 id="next" tabindex="-1">Next <a class="header-anchor" href="#next" aria-label="Permalink to “Next”">​</a></h2><ul><li><a href="/getting-started/how-pikacss-generates-css.html">How PikaCSS Generates CSS</a> — the runtime model behind the output file.</li><li><a href="/integrations/unplugin.html">Unplugin</a> — build-tool options including <code>scan</code>, <code>tsCodegen</code>, and <code>cssCodegen</code>.</li><li><a href="/integrations/nuxt.html">Nuxt</a> — the Nuxt module&#39;s auto-wiring.</li></ul>',20)])])}const g=t(s,[["render",r]]);export{p as __pageData,g as default};
